import type React from 'react';
import { useCssScope } from '../config-provider/hooks';
import { isNonNullable, toFlatArray } from '../util';
import type { TreeNodeProps, TreeProps } from './interface';

export function useTreeCssScope() {
  return useCssScope('tree');
}

export const UD_TREE_NODE_ID = 'UD_TREE_NODE';
function isTreeNode(node: any): node is React.ReactElement<TreeNodeProps> {
  return node?.type?.[UD_TREE_NODE_ID];
}

export function treeChildren2TreeNodes(children: React.ReactNode): NonNullable<TreeProps['treeData']> {
  return toFlatArray(children)
    .map((child, index) => {
      if (isTreeNode(child)) {
        const {
          key,
          props: { children: _children, ...restProps },
        } = child;
        return {
          ...restProps,
          children: treeChildren2TreeNodes(_children),
          key: key || restProps.value || `tree-node-key-${index}`,
        };
      }
      return null;
    })
    .filter(isNonNullable);
}
